            <div className="flex flex-col min-w-0">
              <h1 className="text-[13px] xs:text-lg sm:text-2xl md:text-3xl lg:text-4xl xl:text-5xl font-black text-tuc-maroon dark:text-white uppercase tracking-tighter leading-none whitespace-nowrap overflow-hidden text-ellipsis">
                Techbridge <span className="text-tuc-gold">University College</span>
