                </div>

                <ThemeToggle />
                <button onClick={toggleChat} className="p-2.5 bg-tuc-maroon/5 text-tuc-maroon dark:text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon rounded-full transition-all" aria-label="Toggle AI Chat Assistant">
