            <a href={SOCIAL_LINKS.tiktok} target="_blank" rel="noopener noreferrer" className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" aria-label="TikTok" title="Follow on TikTok"><TikTokIcon size={14} /></a>
            <a href={SOCIAL_LINKS.linkedin} target="_blank" rel="noopener noreferrer" className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" aria-label="LinkedIn" title="Follow on LinkedIn"><Linkedin size={14} /></a>
          </div>

          <div className="flex-1 lg:flex-none flex justify-end lg:block py-3">
            <a href="https://portal.aucdt.edu.gh/admissions/#/home" className="bg-tuc-gold text-tuc-maroon px-8 py-2.5 rounded-[0.75rem] font-black text-[11px] hover:bg-white transition-all shadow-lg uppercase tracking-widest whitespace-nowrap focus:ring-4 focus:ring-white/50 focus:outline-none">Apply Now</a>
          </div>
        </div>
      </nav>

      {/* Mobile Drawer Menu */}
      <div 
        ref={mobileMenuRef}
        tabIndex={-1}
        className={`lg:hidden fixed inset-0 z-[110] bg-white dark:bg-tuc-dark pt-20 px-6 overflow-y-auto transition-transform duration-300 ${isMobileMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}
