        <div className="flex flex-col space-y-6 text-left pb-12">
          <div className="mb-8 border-b border-gray-100 dark:border-gray-800 pb-8 flex items-center gap-6">
            <img src={LOGO_URL} alt="TUC" className="h-28 w-auto object-contain" />
            <div>
              <h2 className="text-xl font-black text-tuc-maroon dark:text-tuc-gold uppercase leading-tight">Techbridge <br/> University</h2>
              <p className="text-gray-400 italic text-[10px] mt-1 font-bold uppercase tracking-widest">Design and Build a Nation!</p>
            </div>
          </div>

          <div className="flex items-center justify-between mb-4">
            <ThemeToggle />
            <button onClick={toggleChat} className="p-3 bg-tuc-gold/15 text-tuc-maroon dark:text-tuc-gold rounded-2xl shadow-sm">
              <MessageCircle size={22} />
            </button>
          </div>

          {NAV_ITEMS.map((item, idx) => (
            <div key={idx} className="border-b border-gray-100 dark:border-gray-800 pb-3">
