                                onClick={() => {
                                  setIsSearchVisible(false);
                                  setSearchTerm('');
                                }}
                              />
                            </li>
                          ))}
                        </ul>
                      ) : (
                        <div className="p-4 text-xs font-bold text-gray-400 text-center italic">
                          No matches found
                        </div>
                      )}
                    </div>
