                      role="menu"
                    >
                      {item.children.map((child, cIdx) => (
                        <div key={cIdx} role="menuitem">
                          <NavLink 
                            item={child}
                            onClick={() => setActiveDesktopDropdown(null)}
                            className="block px-6 py-4 text-[13px] font-bold text-tuc-maroon hover:bg-gray-50 transition-colors tracking-tight text-left focus:bg-gray-100 focus:outline-none"
                          />
                        </div>
                      ))}
                    </div>
                  </>
                ) : (
                  <NavLink item={item} className="px-6 py-5 text-[11px] font-black hover:bg-tuc-gold hover:text-tuc-maroon transition-all flex items-center gap-2 uppercase tracking-widest whitespace-nowrap focus:bg-tuc-gold focus:text-tuc-maroon focus:outline-none" />
                )}
              </div>
            ))}
          </div>

          <div className="hidden lg:flex items-center space-x-3 mx-6">
            <SocialLink href={SOCIAL_LINKS.facebook} platform="Facebook" icon={Facebook} className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" />
            <SocialLink href={SOCIAL_LINKS.twitter} platform="X (Twitter)" icon={XIcon} className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" />
            <SocialLink href={SOCIAL_LINKS.instagram} platform="Instagram" icon={Instagram} className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" />
            <SocialLink href={SOCIAL_LINKS.tiktok} platform="TikTok" icon={TikTokIcon} className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" />
            <SocialLink href={SOCIAL_LINKS.linkedin} platform="LinkedIn" icon={Linkedin} className="w-8 h-8 rounded-full border border-tuc-gold/40 flex items-center justify-center text-tuc-gold hover:bg-tuc-gold hover:text-tuc-maroon transition-all duration-300" />
          </div>

          <div className="flex-1 lg:flex-none flex justify-end lg:block py-3">
