            <button onClick={toggleChat} className="p-3 bg-tuc-gold/15 text-tuc-maroon dark:text-tuc-gold rounded-2xl shadow-sm">
              <MessageCircle size={22} />
            </button>
          </div>

          {NAV_ITEMS.map((item, idx) => (
            <div key={idx} className="border-b border-gray-100 dark:border-gray-800 pb-3">
              <div className="flex justify-between items-center py-3">
                {item.children ? (
                  <button 
                    onClick={() => setActiveMobileSubmenu(activeMobileSubmenu === idx ? null : idx)}
                    className="text-lg font-black text-tuc-maroon dark:text-white uppercase flex-1 text-left tracking-tighter"
                    aria-expanded={activeMobileSubmenu === idx}
                  >
                    {item.label}
                  </button>
                ) : (
                  <NavLink item={item} onClick={closeMobileMenu} className="text-lg font-black text-tuc-maroon dark:text-white uppercase flex-1 tracking-tighter" />
                )}
                {item.children && (
                  <button 
                    onClick={() => setActiveMobileSubmenu(activeMobileSubmenu === idx ? null : idx)} 
                    className="p-2 text-tuc-maroon dark:text-tuc-gold"
                    aria-label={`Toggle ${item.label} submenu`}
                  >
                    <ChevronDown size={22} className={`transition-transform duration-300 ${activeMobileSubmenu === idx ? 'rotate-180' : ''}`} />
                  </button>
                )}
              </div>
              {item.children && activeMobileSubmenu === idx && (
                <div className="bg-gray-50 dark:bg-gray-800/50 rounded-2xl p-6 mt-3 space-y-4 animate-fade-in-up border border-gray-100 dark:border-gray-700">
                  {item.children.map((child, cIdx) => (
                    <NavLink key={cIdx} item={child} onClick={closeMobileMenu} className="block text-sm text-tuc-maroon dark:text-gray-300 font-bold uppercase tracking-tight" />
                  ))}
                </div>
              )}
            </div>
          ))}
          <div className="flex justify-center space-x-6 py-6 border-t border-gray-100 dark:border-gray-800 mt-4">
             <SocialLink href={SOCIAL_LINKS.facebook} platform="Facebook" icon={Facebook} size={20} className="text-tuc-maroon dark:text-tuc-gold transition-transform hover:scale-110" />
             <SocialLink href={SOCIAL_LINKS.twitter} platform="X (Twitter)" icon={XIcon} size={20} className="text-tuc-maroon dark:text-tuc-gold transition-transform hover:scale-110" />
             <SocialLink href={SOCIAL_LINKS.instagram} platform="Instagram" icon={Instagram} size={20} className="text-tuc-maroon dark:text-tuc-gold transition-transform hover:scale-110" />
          </div>
          <a href="https://portal.aucdt.edu.gh/admissions/#/home" target="_blank" rel="noopener noreferrer" onClick={closeMobileMenu} className="block w-full bg-tuc-maroon text-white text-center py-5 rounded-[1.25rem] font-black uppercase tracking-[0.2em] shadow-xl mt-4 active:scale-95 transition-transform">Start Application</a>
          <button onClick={closeMobileMenu} className="flex items-center justify-center gap-2 text-gray-400 font-bold py-6 uppercase text-[10px] tracking-widest w-full"><X size={18} /> Close Navigation</button>
        </div>
      </div>
    </header>
  );
};

export default Header;

